const fs = require('fs');
const crypto = require('crypto');
const content = fs.readFileSync('.tmp/sessions/01aeadd3/plan.md', 'utf8');
// Normalize: remove auto-review markers, Approval Status value, checkboxes
let normalized = content.replace(/<!-- auto-review:.*?-->/g, '');
normalized = normalized.replace(/Approval Status:.*/g, 'Approval Status:');
normalized = normalized.replace(/\[x\]/g, '[ ]');
const hash = crypto.createHash('sha256').update(normalized).digest('hex').slice(0, 12);
console.log(hash);
"

